// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {SymTest} from "halmos-cheatcodes/SymTest.sol";
import {Test} from "forge-std/Test.sol";
import {{TARGET_CONTRACT}} from "../src/{TARGET_FILE}.sol";

/// @custom:halmos --solver-timeout-assertion 10000
contract {INVARIANT_NAME}Test is SymTest, Test {
    {TARGET_CONTRACT} target;
    address[3] internal holders = [address(0x1001), address(0x1002), address(0x1003)];

    function setUp() public {
        target = new {TARGET_CONTRACT}({CONSTRUCTOR_ARGS});
        {SETUP_SEED_STATE}   // Pass B fills: balances, oracle prices, paused flag, etc.
        targetContract(address(target));  // only for driver_shape == stateful_invariant
    }

    // ============================================================
    // PATTERN A — single_tx_check  (CLEAN_SAFETY, single function call)
    // ============================================================
    /// @custom:halmos {DIRECTIVES}
    function check_{name}({SYMBOLIC_ARGS}) public {
        {PRECONDITIONS}                          // require(...) / vm.assume(...)
        {PRE_STATE_SNAPSHOTS}                    // uint256 before = target.X();
        (bool ok,) = address(target).call(
            abi.encodeWithSelector(target.{TARGET_FN}.selector, {ARGS})
        );
        vm.assume(ok);                           // prune revert paths
        // STRUCTURAL INVARIANT (bound from prior.solidity_expr):
        assert({INVARIANT_EXPR});
    }

    // ============================================================
    // PATTERN B — stateful_invariant  (arbitrary call sequence)
    // ============================================================
    /// @custom:halmos --invariant-depth 3
    function invariant_{name}() public view {
        assert({INVARIANT_EXPR});
    }

    // ============================================================
    // PATTERN C — custom_attacker  (reentrancy / callback shapes)
    // ============================================================
    // (Attacker contract defined alongside; fallback re-enters via
    //  svm.createCalldata + vm.assume(success))
    function check_{name}_reentrancy() public {
        Attacker atk = new Attacker(address(target));
        {SETUP_FOR_ATTACK}
        uint256 balBefore = address(target).balance;
        atk.go();
        assert({INVARIANT_EXPR});               // e.g. balance bounded by single refund
    }

    // ============================================================
    // PATTERN D — scripted_trace  (specific ordered sequence, e.g. first-depositor)
    // ============================================================
    function check_{name}_trace({SYMBOLIC_PARAMS}) public {
        vm.assume({PARAM_BOUNDS});
        // Trace from TLA+ counterexample, verbatim:
        {STEP_1}
        {STEP_2}
        {STEP_N}
        assert({INVARIANT_EXPR});
    }
}

// Optional Attacker contract for PATTERN C
contract Attacker is SymTest, Test {
    address public targetAddr;
    uint256 public depth;
    constructor(address t) { targetAddr = t; depth = 2; }
    fallback() external payable {
        if (depth == 0) return;
        depth--;
        bytes memory data = svm.createCalldata(targetAddr);
        (bool ok,) = targetAddr.call(data);
        vm.assume(ok);
    }
}

// =====================================================================
// Constraints Pass B MUST observe when filling this template:
//   1. NAMING: function MUST start with check_ (stateless) or invariant_ (stateful).
//   2. SYMBOLIC ARGS: prefer plain function params (auto-symbolic). Reserve svm.create*
//      only for setUp(), bytes/string (must specify byteSize=1024), or named symbols.
//   3. PRECONDITIONS: use require(...) or vm.assume(...). DO NOT use bound() — kills perf.
//   4. EXTERNAL CALLS: (bool ok,) = addr.call(data); vm.assume(ok);  — canonical idiom.
//   5. ARITHMETIC: use MULTIPLICATIVE form (a*d <= b*c) NOT division (a/b <= c/d).
//   6. DYNAMIC BYTES: svm.createBytes(1024, "name") — always specify byteSize.
//   7. KECCAK SLOTS: compute keccak256 DYNAMICALLY, not at compile time.
//   8. ROLE BINDING: prior.solidity_expr uses role names (user, attacker, vault);
//      Pass B substitutes target contract's actual identifiers.
//   9. HOLDERS: fixed 3-address array for symbolic sums (proven tractable in a16z ERC20Test).
//  10. DIRECTIVES: emit /// @custom:halmos lines from prior.halmos_directives.
// =====================================================================
